INSERT INTO proyects (id, name, description, created_at, created_by) VALUES (1, 'Twindustry', 'Proyecto principal Twindustry', '2024-01-01 00:00:00', 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (1, 1, 1, 'Al intentar conectarnos a la Twindrive nos aparece el siguiente error:  0x80070035. No se ha encontrado la ruta de acceso de la red', 'Habilitar la Compatibilidad con el protocolo para compartir archivos SMB 1.0. y Habilitar inicios de sesión de invitado no seguros.', 'Para Habilitar la Compatibilidad con el protocolo para compartir archivos SMB 1.0 tenemos que buscar "Activar o desactivar características de Windows. Busca en la lista "Compatibilidad con el protocolo para compartir archivos SMB 1.0/CIFS". Despliega la rama y marca las tres casillas (Cliente, Servidor y Eliminación automática). Reinicia el PC.  Para Habilitar inicios de sesión de invitado no seguros tenemos que presionar Win + R y escribir gpedit.msc. Luego ve a: Configuración del equipo > Plantillas administrativas > Red > Estación de trabajo Lanman. Busca la directiva: "Habilitar inicios de sesión de invitados no seguros". Haz doble clic, selecciona Habilitada y dale a Aceptar.', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 1, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (2, 1, 2, 'A pesar de runear los robots en FanucConnect, no aparecen en el DSCLient', 'Reinstalar Fanuc Robot Interface', 'Se ha actualizado de forma automática Windows: Windows 11, versión 25H2. Al actualizarse, provoca que no se vean. Con desisntalar y volver a instalar la aplicación Fanuc RObot INterface, vuelve a funcionar todo correctamente', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 2, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (3, 2, 3, 'Necesitamos saber las unidades de velocidad de las surfaces y de los motion joint para que el PLC pueda asignarle velocidades deseadas', 'Abrir ticket de Fe Screen Sim', '1. Los movimientos de traslación de los motion joint son en metros por segundo                                                   2. Los movimientos de rotación de los motion joint son en grados por segundo.                                                       3. La velocidad de las surfaces son en metros por segundo', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 3, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (4, 2, 4, 'Necesitamos crear varias pilas de un mismo producto para realizar diferentes pruebas', 'Añadir una template de cada pila dentro de un sequence inserter', 'Para crear pila de productos, debemos añadir dentro del sequence inserter una template por cada tamaño de pila que se quiera añadir. Para ello, la forma de hacerlo es colocar un sequence inserter e ir soltando producto a producto hasta forma la pila deseada. Una vez tenemos el tamaño de pila que queremos tenemos que establecer el producto que esté en la base como padre del resto. Este padre debe tener la opción "Is kinematic" en OFF, mientras que todos los hijos deben tenerlo en ON.', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 3, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (5, 2, 5, 'Tenemos el problema de que cuando se desactiva el enable de este bloque, la velocidad no pasa a cero sino que se queda congelada en el valor que tenía', 'Estudio del funcionamiento del Bloque', 'El problema se soluciona haciendo que la señal de enable siempre sea true y que la señal que varíe de true a false sea MotorRunning. De este modo, cuando MotorRunning sea true el motor acelera y cuando sea false el motor desacelera. En las librerías ofrecidas por FE existe una lógica en C# donde se puede ver en código el funcionamiento de este bloque.', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 3, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (6, 2, 6, 'El gripper está activo pero cuando toca la pieza no la coge', 'El Gripper funciona con un flanco de subida', 'Para que el gripper haga el attach, necesita que la pieza (payload) a coger se encuentre dentro de su rango de acción y recibir la señal de active en ese momento. Si entra con el valor Active a true a coger la pieza no la cogerá porque no recibe el flanco de subida', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 3, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (7, 2, 7, 'Cuando añadimos una señal de tipo String o Char a la interfaz e intentamos conectar con PLCSIM Adv, recibimos el error de que ese tipo de variable is not supported', 'Cambiar la señal a INT en el PLC', 'Es un problema por parte de Siemens y el programa PLCSIM Advanced. La solución que se adoptó fue cambiar desde PLC la variable a INT y dentro de FE hacer una lógica para clasificar según el INT recibido.', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 3, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (8, 2, 8, 'Tenemos dos formas distintas para añadir objetos en la escena, mediante un sequence Inserter o usando la lógica de CreationPayloadFromXML. Según el tipo de payload que queramos crear, utilizaremos uno u otro.', 'Diferenciar los casos de uso', 'Sequence Inserter: Es muy útil cuando tenemos el caso de pilas de payloads. Este objeto nos permite crear pila de payloads, en los cuales hay uno que sería la base (Padre) y el resto irían apilados encima (hijos).  Lógica de creación mediante XML: Esta forma es muy útil para con un simple botón hacer aparecer todos los payloads en ciertos puntos del material flow, pero no permite crear pilas de productos conservando la jerarquía de padre-hijo.', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 3, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (9, 2, 9, 'Cuando intentamos crear una pila de piezas sobre un BaseBoard y hacemos todos las piezas hijas del Baseboard para que pierdan las físicas y poder moverlas, el BaseBoard se hunde en la surface y no recupera la posición.', 'Utilizar un bumper entre piezas y ajustar manualmente las piezas', 'El proceso de construcción será el siguiente: primero colocaremos el baseboard y sobre él, iremos generando las piezas que queremos trasnportar. Una vez hecho esto, se hundirá el baseboard, pero sólo tendremos que coger todas las piezas y desplazarlas en z hasta que el baseboard recupere su posición', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 3, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (10, 2, 10, 'Cuando configuramos en el Auto Assigment una expresión, parece que sólo funciona la conexión si se clicka sobre la slot o la variable correspondiente', 'Lo que vemos es un preview de lo que se conectará cuando ejecutemos el assingment', 'Cuando tenemos la expresión definida, desde el Expression Editor podemos ir clickando sobre los Slots y Variables para ver un preview de lo que esa expresión devolverá, que será un "false" o el nombre que queremos conseguir', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 3, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (11, 2, 11, 'No comprendía el funcionamiento del apartado I/O Generator y su posible uso a la hora de automatizar la creación de interfaces y señales de PLC', 'Reunión con FE para entender el funcionamiento y su posible uso', 'Esta pestaña se utiliza para crear a partir de un SceneObject las entradas que irán conectadas dentro una interfaz. Esta pestaña no será necesaria si se posee un Excel con las variables de entrada y salida.', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 3, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (12, 2, 12, 'El PLC se comunica con variadores a través de telegramas y no tiene Tags a los que se pueda acceder desde FE', 'El PLC está escribiendo esos telegramas en un rango de direcciones aunque no haya Tags', 'Aunque no existan Tags, si los telegramas se envían en un rango de direcciones, ese rango de direcciones se puede leer desde FE sin necesidad de que el PLC tenga que crear Tags', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 3, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (13, 2, 13, 'Hay muchas conexiones que estaban hechas que aparecen desconectadas sin motivo aparente', 'Auto-Assigmnet realiza la desconexión de los assigments que estén inactivos', 'Al realizar Auto-Assigments, hay que tener en cuenta que si hay conexiones que ya hemos realizado con anterioridad y dejamos inactivo ese assigment, se desconectarán todas las conexiones que ese assigment había hecho', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 3, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (14, 2, 14, 'Da error al importar el Excel con los variables del robot en Kuka Interface', 'La columna de Tag debe ser la columna B del Excel y después seguir el orden', 'Para que la importación se realice correctamente, debemos colocar la columna de Tag en la columna B y, a partir de ahí, continuar con el mismo orden que aparece en Kuka Interface', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 3, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (15, 2, 15, 'Al importar el Excel directamente en Kuka Interface no se importa la columna de Usage', 'Usar "Compare with Excel" para colocar el valor de Usage', 'Una vez importado el Excel, tenemos que usar el botón "Compare with Excel" que aparece a la derecha. Importamos el mismo Excel importado en la interfaz y pulsamos en "Compare by Tag" y cuando haya finalizado, pulsamo en "Merge Variables" consiguiente que se complete la columna Usage', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 3, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (16, 2, 16, 'Es necesario hacer que el payload sea un elemento raíz para que recupere las físicas', 'Usar un Pick&Place para hacerlo de nuevo elemento raíz', 'Tenemos que configurar el Pick&Place colocanda el "Pick Mark" la marca del payload y en "Drop Mark" dejarlo vacío, de modo que después de hacer un pick y un drop posterior, el payload vuelve a ser un elemento raíz', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 3, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (17, 3, 17, 'El DS Client que no está en el host para continuamente la comunicación con el DS Server y el DS Client que está en el host dando un fallo relacionado con la red (red lenta o red saturada)', 'Modificar los parámetros del adaptador de red, tanto del host como del guest.', 'En el adaptador de red correspondiente, vamos a las propiedades (click derecho - Propiedades -> Configurar… -> Opciones avanzadas) y modificamos las siguiente: - Moderación de interrupción: Seleccionamos "Desactivado" - Velocidad dùplex: Seleccionamos "1.0 Gbps Full Dúplex"', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 4, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (18, 4, 18, 'Los robots de soldadura piden continuamente capchange', 'Forzar siempre a false los technobits 8 y 9 de la tecnología que nos digan (A,B,C...) que sea la de soldadura en ese robot', '1. Buscar cuál es la letra de tecnología(A,B,C...) que corresponde a welding (soldadura) 2. Asignar los technobits 8 y 9 (confirmarlo con PLCer@) a FALSE 3. Eliminar las señales del bloque de tecnologías para que no se sobreescriban', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 2, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (19, 5, 19, 'A Roboguide no le llegan las señales que le envía ViPeR pero a ViPeR si le llega las señales que le envía Roboguide', 'Al configurar los robots en Fanuc Connector hay que pulsar el botón "SET DI AND GI SIGANLS AS "SIMULATED""', '1. Desconectar robots de FANUC Connector y parar los robots en Roboguide 2. Rellenar los huecos correspondientes para cada robot en el apartado Configure de Fanuc Connector 3. Pulsar el Botón Configure. 4. Pulsar el Botón "SET DI AND GI SIGNALS AS "SIMULATED"" 5. Conecta el robot y ya funcionará correctamente la comunicación entre ViPeR y Roboguide', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 1, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (20, 6, 20, 'Necesitamos realizar el Fanuc Setup en todos los robots e instalar las tecnologías de cada uno de ellos.', 'Todo viene explicado en el archivo VIBN Workflow_v9.16', '1. STOP MAKRO STEP y MAKROs SPS. 2. Fanuc Setup: Menu-> 7 File -> 1 File-> Fanuc Setup en MC: 3. Funktion: Install y next. 4. Instalar Config_GE_ALLG y next. 5.  Instalar Config_ALLG y luego en función de la tecnología se añade: 5.1 Si es Gripper, Config_Greifer. Next y Restart Controller. 5.2 Si es Masilla, Config_KL1. Next y Restart Controller. 5.3 Si es Soldadura, Config_EZSP1, Config_KW1 y Config_RZ1. Next y Restart Controller. 6.1.  Para la Gripper no hay que configurar más 6.2. Rellenar TCP Speed Parameters como viene en el archivo VIBN Workflow_v9.16. Luego ve a Menu->VAG Config->ServoGun y añade el nombre del soldador,pulsa a apply y restart Controller. Para terminar mira que en Menu->Next->Status->Gun Change la Gun2 aparece attacheada y que en Menu->VAG Config-> Gun Information la Gun No.2 esté activo. 6.3.  Añadir GUN_Master.LS y correr programa. Luego,  7. Añadir Makro998 y unprotect. Run de nuevo MAKRO STOP y MAKROs SPS. 8. Revisa que en Menu->Next->System->DCS todos los apartados se encuentre como viene en la documentación VIBN Workflow_v9.16', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 1, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (21, 7, 21, 'Los SINAMICS dan error si creamos el proyecto de HW a través del formato AML (el utilizado hasta ahora)', 'Hay que crear el proyecto de Hardware con el formato XML.', 'Se debe de tener instalado el Software: Simulation Unit y compilar el programa del PLC en el mismo ordenador donde dicho software está instalado. Aún así, a J.Marmol le ha sido imposible obtener el fichero xml y EKS lo ha generado para nosotros.  UPDATE: EKS ha mandado una guía sobre como solucionar los problemas para la generación del fichero xml en windows 10 (04.04.2024)', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 5, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (22, 7, 22, 'El programador ha cambiado la dirección en algún dispositivo hardware', 'Editar archivo AML de hardware', 'Vamos al archivo al archivo AML y buscamos por nombre el dispositivo en el archivo, unas lineas mas abajo veremos como se define la primera posición I/O y el numero de BITs que se van a utilizar. Debemos modificar la dirección a la deseada y guardamos los cambios. Tras esto vamos al portal de la FS BOX y editamos el proyecto recargando el archivo con las modificaciones realizadas.', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 6, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (23, 8, 23, 'El administrador no es miembro del grupo de usuarios "Siemens Tia Openness"', 'Añadir el usuario a dicho grupo de usuario', '1. Abrir administrador de equipos. 2. Clicar en "Usuarios y grupos locales" y posteriormente en la carpeta "Grupos". 3. Busca el nombre "Siemens Tia Openness" y pulsa el botón "Agregar". 4. Pulsa opciones avanzadas y posteriormente a "Buscar ahora". 5. Añade el usuario correspondiente y reinicia el pc.', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 1, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (24, 9, 24, 'Errores al importar el fichero AML de HW obtenido mediante la herramienta TIA Exporter.', 'Eliminar los componentes HW que generen error (siempre y cuando no tengan interfaz física de direcciones. Ej: IPC, HMI, Switch)', 'Eliminar del fichero AML con el bloc de notas siguiendo las indicaciones de Línea que nos da la FS Box cuando intentamos importar el archivo AML', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', NULL, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (25, 10, 25, 'Es necesario el uso de las licencias de la Suite de EKS en cada uno de los ordenadores', 'Creación de un servidor de licencias a partir del software CodeMeter', '1. Abre la aplicación Codemeter. 2. Pulsa el botón inferior de la derecha "WebAdmin"  3. Vete a la ventana de "Configuration" y añade en la pestaña de "Server Search List" la IP 192.168.0.113 . 4. En la parte de debajo de dicha página, en "Current Server" pulsa el botón de intercambiar. 5. Pulsa como server encontrado la dirección IP añadida anteriormente y dale al botón "Apply".   Con todos estos pasos ya se deberían tener todas las licencias. Si se tiene un problema de seguridad al pulsar el botón "WebAdmin" en el paso 2 se soluciona descargando el explorador Google Chrome.', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 1, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (26, 11, 26, 'Todos los bloques comunican correctamente menos el PN-PN-Coupler, habiéndole añadido DPDPID, START_ADDR_IN y START_ADDR_OUT tanto en el RCV como en el SEND.', 'Cambiar de v2.0 a v3.0 el FB del SEND y del RCV en el proyecto de TIA.', 'Para que la comunicación entre PLC y ViPeR con PLCSIM Advanced del PN-PN-COUPLER tanto el SEND como el RCV tienen que tener la versión 3.0 en el FB. Cambiando la versión de la 2.0 a la 3.0 comunica bien.', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 1, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (27, 12, 27, 'Creación de instancia para Virtual en PLC Sim Advanced (Sustituye a FSBOX)', 'Configurar los adaptadores de ethernet y ethernet virtual,  configurar PLCsim Advanced y crear la instancia del proyecto, establecer las comunicaciones pertinentes', 'Abrir PLC Sim Advanced, asegurarnos de que la opción de Virtual Eth. Adapter esta selececcionada, escogemos el adaptador "Ethernet" para la comunicación TCP/IP, introducimos el nombre exacto del proyecto (PLC y Viper, por lo general 49-01CELDAX), la IP del proyecto la cual proporcionará el PLCero y la máscara de subred (255.255.255.0). Posteriormente pulsamos start y comprobamos que el indicador aparezca en verde. Para el resto de la comunicación, debemos abrir PSABridge y ejecutar RunMode, así como abrir FS:Connect, introducir el nombre exacto del proyecto (PLC, Viper y PLCSim) pulsar Start. Por último debemos asegurarnos de que las IP del adaptador Ethernet y de un nuevo adaptador virtual que se ha generado estén en el mismo rango (Penúltimo trío de numeros) y que su mascara de subred sea 255.255.255.0', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 7, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (28, 12, 28, 'Al instalar sale "Error desconocido"', 'https://support.industry.siemens.com/forum/es/en/posts/plcsim-advanced-an-error-occurred-while-installing/326347?viewmode=print', '1. Ejecutar CMD como Administrator  2. Copiar y pegar el siguiente comando cd C:\Program Files\Common Files\Siemens\PLCSIMADV\Drivers Siemens.Simatic.PlcSim.Advanced.DriverInstaller.exe install  3. Reiniciar el ordenador cuando se haya completado la instalacion', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 6, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (29, 12, 29, 'Error: The "Automation License Manager Service" has not been started! Please start the Service.', 'https://support.industry.siemens.com/cs/ww/en/view/114358', '1. Desinstalar AML (Automation License Manager) desde el panel de control.   2.  Eliminar la carpeta "Automation License Manager" que se encuentra en la siguiente ruta:  C:\Archivos de programa\Siemenes\Automation\ 3.  Eliminar la carpeta "almsrv" que se encuentra en la siguiente ruta: C:\Archivos de programa\Common Files\Siemenes\sws\ 4. Reiniciar el ordenador 5. Instalar el nuevo ALM del enlace. (Imagen original de los pasos a seguir incluida)', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 8, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (30, 12, 30, 'Al crear una instancia del PLC, aparece este error en la esquina inferior derecha', 'Refrescar el cable Ethernet usado en la comunicación TCP/IP', 'En el apartado de comunicación TCP/IP debe aparecer el cable que tenemos conectado al PLC. El procedimiento será cambiar ese Ethernet que tengamos a otro disponible, nos pedirá permiso para hacerlo y lo concedemos. Una vez hemos cambiado el Ethernet de comunicación, tenemos que volver a asignar el puerto que está conectado con el PLC, volverá a solicitar permiso para hacerlo y se lo concedemos. Una vez realizado este procedimiento podremos crear la instancia sin problema.', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 3, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (31, 12, 31, 'Al crear una nueva instancia no creada antes, TIA Portal da un error al intentar conectar con PLCSIM Advanced', 'Cargar primero el hardware en la instancia creada', 'Algunas veces al crear una nueva instancia en PLCSIM Advanced da un error al conectar con TIA Portal. Para evitar este error, hay que primero hacer un load del hardware y, una vez realizado, podremos ver como aparece que ha sido cargado correctamente y podemos realizar el load del software. De este modo, veremos como aparece en verde la instancia en PLCSIM Advanced.', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 3, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (32, 12, 32, 'Instancia de PLC "Congelada". El PLC pierde conexion.', 'Activar reinicio automático del servicio', 'Durante la ejecución, podremos ver que la instancia del PLC aparece en gris en PLCSim Advanced y el Tia Portal pierde conexión con el. Para solucionarlo seguimos los siguientes pasos: 1. Borrar la instancia de PLC (No hace falta borrar los datos de la carpeta Virtual Simatic Memory Card). 2. Abrimos el administrador de tareas y en la barra lateral izquierda (O superior dependiendo de la versión de windows) nos vamos a la pestaña servicio. 3. En esta pestaña debemos buscar el servicio "almservice" que aparecerá como detenido. Hacemos click derecho->Abrir servicios. 4. En la nueva pestaña tendremos que buscar el servicio "Automation License Manager" y volveremos  a hacer click derecho->propiedades. En esta nueva pantalla nos iremos a la pestaña de "Recuperación. 5. En esta pestaña nos aparecen 3 desplegables, para seleccionar la respuesta tras errores. Tendremos que seleccionar en las 3 pestañas la opción "Reiniciar el servicio" y aplicaremos los cambios. 5. Una vez finalizado el proceso, podemos volver a crear la instancia del PLC.', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 3, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (33, 13, 33, 'No tenemos licencia de Roboguide', 'Si formateamos el ordenador, conseguimos 30 días de licencia gratis, por lo que tenemos licencias infinitas', '1. Cuando le queden pocos días a la licencia de prueba, tenemos que guardar el proyecto de Roboguide en la Twindrive y formatear el equipo solo las aplicaciones. 2. Luego, ya formateado el ordenador, hay que descargar DS Client y FanucConnect de la Suite de EKS. 3. Por otro lado, hay que descargar Roboguide 9.4, KukaRobotInterface de Fanuc (Para ello, anteriormente hay que realizar los pasos que vienen en el documento prerequisitos Roboguide) y copiar el proyecto de Roboguide de la Twindrive de nuevo al equipo. 4. Después, hay que descargarse TeamViewer y configurarlo para tener acceso con una contraseña fija. 5. También hay que cambiarle la IP al adaptador Ethernet que esté conectado con el PC del Virtual para que coja las licencias y comunique DS Client y FanucConnect y en Codemeter en el apartado de Configuración eliminar la IP que busca en todos los servidores licencias y añadir la IP del PC del virtual donde se encuentran las licencias. 6. Por último, hay que comprobar desde otro ordenador que nos podemos conectar por TeamViewer, comprobar que comunica DS Client y abrir unas de las instancias de robot de Roboguide para ver que tenemos 30 días de licencia de nuevo.', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 1, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (34, 14, 34, 'De dónde se obtienen esos ficheros?', 'Los archivos Machine.dat y Config.dat (necesarios para la correcta creación de Robsim) vienen en conjunto con las celdas de Process Simulate.', 'Si se descomprime el Process (PSZX), veremos que dentro de la carpeta Library existe una carpeta llamada Robot Machine Data. Dentro de esa carpeta encontramos información sobre a qué Robot pertenece y los ficheros mencionados.', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', NULL, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (35, 14, 35, 'RobotInfo / Machine.dat', 'Como averiguar a qué tipo de Robot pertenecen determinados OLPs', 'Sabiendo el nombre del Robot (especificado en OLPs) podemos ir a la carpeta de Robot Machine Data (del process simulate) e ir buscando dentro de Robot Info o Machine.Dat el tipo de Robot hasta que se encuentre el que coinciden. Una vez ha pasado eso exportar los ficheros config.dat & machine.dat respectivamente', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', NULL, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (36, 14, 36, 'Diferentes errores que han aparecido en RobSim tras realizar la compilación de los controladores de los robots.', 'Creación de un PowerPoint', 'Creación de un PowerPoint con la solución de algunos de los problemas que han aparecido en la compilación de los controladores en RobSim. Este PowerPoint se encuentra dentro de la carpeta de "Tech_Data"  con el nombre de "Errores_compilación_RobSim".', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 1, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (37, 14, 37, 'Como detectar si un Robot es de KE o SZ o que tecnología tiene', 'Se puede comprobar en Robsim si el Robot es de KE o SZ con una variable local', 'Añadir a PPT de ROBSIM', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', NULL, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (38, 14, 38, 'El modelo de Robot no es correctamente detectado por RobSim Assistant. Posibles motivos:  -No se ha añadido los ficheros de machine.dat & config.dat -No se reconoce textualmente el modelo de Robot especificado en machine.dat', 'Modificar el nombre del tipo de Robot en el fichero machine.dat de cada Robot para qe los reconozca.', 'Se coge el nombre o bien de la lista de los modelos de Robot de Robsim o directamente del excel que indique el nombre del modelo del Robot. Si todo funciona en el asistente de Max2 de Robsim debería aparecer que la creación de los ejes externos ha funcionado.', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 5, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (39, 14, 39, 'Hay un parámetro sobre la velocidad del 7ª eje de Robots que viene por defecto al 30% y hace que los Robots se muevan muy lento.', 'Modificar el archivo: machine.dat/&config.dat del Robot', ': "RedVelExAx[1]" hay que ponerla a 100', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 5, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (40, 14, 40, 'Al usar los backups de los robots en lugar de los OLPs, los robots durante el virtual dejan de devolver la señal de fin de secuencia Fertigmeldung, esencial para la ejecución del programa del PLC.', 'Modificar los archivos \KRC\STEU\Mada\$custom.dat de cada robot', 'En el archivo \KRC\STEU\Mada\$custom.dat de cada robot, buscar las líneas: $BIN_OUT[18]={F_BIT 33,LEN 4,PARITY #NONE} y $BIN_OUT[19]={F_BIT 97,LEN 16,PARITY #NONE} por $BIN_OUT[18]={F_BIT 1,LEN 0,PARITY #NONE} y $BIN_OUT[19]={F_BIT 1,LEN 0,PARITY #NONE} respectivamente. Además, el robotero tiene que escribir el FM que toca no uno genérico.', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 7, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (41, 14, 41, 'Al usar los backups de los robots en lugar de los OLPs, los robots durante el virtual dejan de devolver la señal de eco de la Folge que están empleando, esencial para la ejecución del programa del PLC.', 'Modificar los archivos \KRC\STEU\Mada\$custom.dat de cada robot', 'En el archivo \KRC\STEU\Mada\$custom.dat de cada robot, buscar la línea: $BIN_OUT[19] y asegurarnos de que es exactamente así:  $BIN_OUT[19]={F_BIT 1,LEN 0,PARITY #NONE}. Este problema se soluciona al solucionar los Fertigmeldung pero puede darse sin que estos fallen.', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 7, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (42, 14, 42, 'Error en RobSIM cuando se carga BackUps de robots', 'Comentar cóidgo que da fallo en los robots..', 'Comentar las líneas donde aparece MQTT CONFIG y MOVE ON DETECT.', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 1, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (43, 14, 43, 'Ya tenemos el archivo completo de Robsim y recibimos un nuevo robot para añadir al proyecto', 'Creación de otro proyecto de RobSIM (hacen falta dos licencias)', '1. Crear un proyecto de RobSIM con el robot que quieres añadir. 2. Dentro de carpeta HMI y SRC coger la carpeta corresponiente al robot añadido. 3. Pegad estas carpetas en las carpetas correspondientes de HMI y SRC del proyecto antiguo de RobSIM. 4. Abrir RobSIM nuevo, click derecho en "RSProject..." -->Properties. Click Izquierdo en el Controlador nuevo y pulsar el botón "Copies the selected controllers to clipboard". 5. Abrir RobSIM antiguo, click derecho en "RSProject..." -->Properties. Pulsa el botón "Pastes controllers from clipboard".', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 10, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (44, 14, 44, 'Al ejecutar el robot, siempre se para en el mismo sitio: ActuateValve>SetValveState>ConfigurationError', 'Software bug. Modificar el archivo dai_Grip.src.', 'La línea 1635 de código debe tener el "[4]", quedando de la siguiente forma: "CHAR chrSource[4];Vc_add [4] ;Specifies the source string to trim"', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 2, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (45, 14, 45, 'Después de un tiempo el robot ejecutándose, salta un error "Runtime error in task "..." en Dai_grip.src, y posteriormente el robot "muere"', 'Software bug. Modificar el archivo dai_Grip.src.', 'Buscar en el archivo DAI_Grip.src del robot la línea "CHAR chrSource[]" y añadir un 4 entre los corchetes, quedando así la línea CHAR chrSource[4]', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 2, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (46, 14, 46, 'Al crear los robots en RobSim Assistance, salta una advertencia de que no ha encontrado el modelo del robot necesario', 'Añadir los modelos de robots faltantes', 'Añadir en el archivo "rFRCModeLIb.txt" (ruta: "C:\Program Files\EKS InTec\MAX2 x64 - RobSim Assistance\Assistances\RobSim\config") el modelo del robot correspondiente que pida Robsim. Este txt por defecto no se peude modificar, por lo que es necesario copiar en otro txt todo, modificarlo y sobreescribir en su lugar. Además, hay que añadir el archivo ".rkin" de cada robot en la ruta "C:\Program Files\EKS InTec\RobSim x64\robots\KUKA\rkin". Los ficheros .rkin se encuentran ubicados en "Z:\01_TechData\Robots Robsim (RKIN)" Si hay algún modelo no encontrado, hay que pedirlo a EKS', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 1, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (47, 14, 47, 'Error "too many arguments" en "vibn_glob_toolchange_couple". El archivo se genera incorrectamente con OLPs.', 'Reemplazar el archivo erróneo por uno correcto', 'Reemplazar los archivos "tool_X_decouple.src" y ".dat" de los robots con docking generados con OLPs con los generados con backups. En este caso, los del B230011, robot 999.', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 2, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (48, 14, 48, 'Recibimos SafeOP después de realizar la creación de RobSIM desde RobSIM Assistance.', 'Añadir en cada controlador el archivo .xml de SafeOP.', '1.  Click derecho en el "RS Controller". 2. Pulsamos Properties. 3. Clicamos en "opens a file dialog to add new source files".  Emoticono de carpeta, primero empezando por la izquierda. 4. Añadimos el .xml correspondiente al safeop de dicho robot y eliminamos el "dummy_saferob" 5. Volvemos a incluir al buildear el puerto de salida "outSafeOpSim"', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 1, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (49, 14, 49, 'Error "not declared iot_point_collector"', 'Comentar las líneas donde se declara el iot_point_collector"', '1. Buscar en src\130RB_100\KRC\R1\System el archivo "DAI_IOT_SUB" 2. Comentar con ";" las líneas del "IF IOT_POINT COLLECTOR", incluyendo las del "IIF (Varstate("proIPTmp.name_C")==#DECLARED) THEN", sin olvidar que hay que cerrar el primer IF con el ENDIF de más adelante, el cual tambien hay que comentar también. Aproximadamente, las líneas deben ser de la 7 a la 13, y la línea 39. 3. El archivo debe quedar como en la imagen de la derecha', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 2, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (50, 14, 50, 'Undefined identifier ''COMMAND''! // Undefined identifier ''Proccess''!', 'Comentar la línea (Son descripciones del proceso)', 'Añadir antes un ;', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 9, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (51, 14, 50, 'Undefined identifier ''_3158476''!', 'Quitar "_" que esta delante del numero', 'Abrir el archivo y borrar la  "_" que esta delante del numero', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 9, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (52, 14, 50, 'Undefined identifier ''XTRANSFERPIONT_1A''!', 'Añadir el punto "XTRANSFERPIONT_1A" al archivo', '1. Abrir el archivo "Inbetriebn" del robot correspondiente en la ruta: RobSim_Daimler_20250807\src\010RB_100\KRC\R1\Program 2. Copiar las posiciones que nos den error(p.ej:XTransferpiont_1A={A1 -95.0,A2 -90.0,A3 115.0,A4 20.0,A5 40.0,A6 -180.0,E1 -3500,E2 0.0,E3 0.0,E4 0.0,E5 0.0,E6 0.0}) 3. Abrir el archivo "global_points.dat" de la ruta: RobSim_Daimler_20250807\src\010RB_100\KRC\R1\System 4. Añadir los puntos copiados en el punto 2 y añadirles delante "DECL GLOBAL E6AXIS". (p.ej:DECL GLOBAL E6AXIS XTransferpiont_1A={A1 -95.0,A2 -90.0,A3 115.0,A4 20.0,A5 40.0,A6 -180.0,E1 -3500,E2 0.0,E3 0.0,E4 0.0,E5 0.0,E6 0.0})', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 9, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (53, 14, 51, 'Robot está runeado y aparece el siguiente fallo: "Runtime Error in task x: Critical Internal error!Task aborted." Aparece una calavera también en el main program.', 'Chequear la consola de robsim para ver donde está la localización precisa del fallo y arreglarlo.', 'When this error occurs, the console may contain a precise location (program, line, column and reason). For example, if an array is out of range, then you need to check why this is the case.  If this error occurs, the robot must be reset to restart it.', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 1, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (54, 14, 52, 'En la HMI de PLC aparece un error de ID incorrecta de la tecnología X (FDS, DS, HSN...), menos GRP/GRH', 'Descomentar la tecnologia correspondiente en el archivo "DAI_DynPlcCom.src"', 'Buscamos el src del robot sobre el que nos esté saltando el fallo y buscamos el archivo "DAI_DynPlcCom.src". Buscamos dentro de ese archivo la tecnología que nos interese. En la mayoría se descomenta la parte completa de la tecnología, pero hay otras que no, por lo que se recomienda copiar y pegar de algún ejemplo que tengamos de robot con la misma tecnología. Además, es importante descomentar tambien la función del finaln del archivo y el "end" previo. No olvides buildear de nuevo los robots!', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 2, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (55, 14, 53, 'En la HMI de PLC aparece un error de ID incorrecta de la tecnología GRP/GRH', '', '', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', NULL, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (56, 14, 54, 'Cambios en el MADA del robot que no se aplican', 'Hay que cambiarlos dentro del robot (Los ejes internos dentro de robsim)', 'El robotero debe cambiar en robsim los ejes correspondientes en el robot que haya realizado las modificaciones ya que al buildear estos cambios no se aplican solos.', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 9, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (57, 15, 55, 'Los robots no tienen asignados nombre de body', 'Hay que añadir en YAMS>Assistance>Interlock, los respectivos robots para que tengan su ref.ID. Una vez hecha esta configuración, hay que volver a importar los datos en SCOUT', 'Debe quedar como en la imagen de la derecha', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 2, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (58, 16, 56, 'Problema para reconocer que hace cada señal debido a que hay muchas siglas y que además vienen de palabras alemanas', 'Documento Traducción Alemán - Español', 'Creación de un documento en el que vienen traducidas todas las siglas al español y más palabras utilizadas frecuentamente en el proyecto.', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 1, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (59, 17, 57, 'Al importar bibliotecas en Viper u otro software da error si el directorio es demasiado largo', 'Acortar directorio', 'Copiar los archivos en un directorio mas corto, como documentos o el escritorio', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 14, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (60, 17, 58, 'En los robots que tienen cambio de gripper se pierde la conexión con el bloque del gripper (todas las salidas del bloque se quedan en negro)', 'Esto se debe a que el bloque del Docking no está bien configurado', 'Abajo del todo en el bloque hay que añadir las señales correspondientes provenientes del YAMS para que el bloque sepa qué gripper lleva puesto el robot', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 10, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (61, 17, 59, 'En PLC recibían Emergency stop en atornilladora (SRS)', 'Girar un switch en la HMI', 'En la HMI, en Drives>SRS correspndiente, girar hacia la derecha el switch nombrado como NOT-HALT. De esta forma pone a false la emergencia. Además, para que reciban CHANNEL OK, forzamos (si no tenemos señal) CH1_WITH_SG1', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 2, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (62, 17, 60, 'El bloque KE de Weldgun no funciona bien al 100% por lo que hay que forzar algunas señales para la M[95] y el Tippchange', 'Añadir la lógica para cada robot con soldadura que podéis encontrar en Descripción de la solución', 'TRUE--------------- `215150R01`.`RI_719` TRUE--------------- `215150R01`.`RI_757` `215150R01`.`RQ_786`--------------- `215150R01`.`RI_787 `215150R01`.`RQ_786`--------O------- `215150R01`.`RI_788 (Negada)', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 1, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (63, 17, 61, 'En el HMI aparece un fallo de que no existe Backup en el robot', 'Borrar del bloque ROBOT_BASIC_FANUC la señal 31 de PLCIN y crear minilógica en el programa Logic.', 'Quitar la señal "`K1TVOL2_PLCIN`.`235190R01_A.A31_Archivierung_beendet`" de todos los robots y añadir en logic para cada robot la siguiente lógica `K1FRKL2_PLCOUT`.`216100R01_E.E31_Anfo_Archivierung` --------------- `K1FRKL2_PLCIN`.`216100R01_A.A31_Archivierung_beendet` - Por último, el PLCero tiene que pulsar en el HMI el botón Archive Robot y desaparecerá el fallo de No Robot Backup.', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 1, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (64, 18, 62, 'No se produce un attach de un conjunto de piezas cuando algunas de ellas han hecho attach previamente. Hay que tener en cuenta que se puede realizar la creación de todo este conjunto de piezas de forma individual desde dicha estación.', 'Creación de dos attach distintos', 'El primer attach será para las piezas que no han sido juntadas anteriormente. El segundo attach será para las piezas que han sido juntadas a otras piezas. Esto se debe a que con la creación de piezas en dicha estación hay que añadir al attach todas las piezas (incluso las que ya han sido unidas a otras) por lo que cuando se realiza la creación de dichas piezas no hay problema pero cuando las piezas van llegando por el transcurso de la celda las piezas que ya han sido unidas ya no existen y no se podrá realizar dicha unión. Por lo que, cuando lleguen las piezas a dicha estación se podrá realizar el primer attach de manera correcta llevándose así todas las piezas aunque el segundo attach no se realice por el problema explicado anteriormente. Y, cuando se creen las piezas de forma individual en la estación se realizarán los dos attach de manera correcta.', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 1, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (65, 18, 63, 'En YAMS, para la creación de productos tenemos que muchos productos aparecen formados por 2,3 o 4 subproductos por lo que para realizar el Material Flow tendríamos que realizar todos estos subproductos por separado teniendo que realizar mucho más trabajo que si todos estos estuvieran unidos.', 'Uso de la herramienta de YAMS "Stonify" para la unión de "bodies"', '1. Creamos un "body" que será el cuerpo del producto unificado. 2. La posición y orientación del "body" debe ser la misma que los cuerpos a unir. 3. Se realiza el "Stonify" de dichos cuerpos. 4. Se crea un attach para este cuerpo cuyo Kinematic Tree debe tener mismo "parent" que los cuerpos que se han unido y cuyo "child" será el nuevo cuerpo creado. 5. Se coloca la posición y orientación del cuerpo en la posición inicial (0,0,0,0,0,0).', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 1, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (66, 18, 64, 'Al iniciar la simulación en YAMS pueden saltarnos errores en la ventana de depuración.', 'Buscar fuente del error', 'Nos vamos a la linea de texto donde está el error en la ventana de depuración y hacemos clicl en el icono de editar, esto nos abrirá el cuadro de edición del objeto que genera dicho error.', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 6, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (67, 18, 65, 'Realizas el Material Flow completo y te das cuenta que uno de los bodies (o la mayoría) que has utilizado no son los correctos debido a que no se crea el producto en el lugar esperado. Hasta ahora si ocurría eso teníamos que borrar todos los bodies (perdiendo tanto las señales de creación, cambio de nombre, los sensores, attach...) y crear de nuevo todo el Material Flow que tuviera el body incorrecto.', 'Utilizar la herramienta "Replace Origin".', 'Para que no tengas que hacer el trabajo doble, si pulsas  en el YAMS el body correcto y, por otro lado, pulsas con el botón derecho del ratón en la "station" cuyo body quieres cambiar, aparece la herramienta REPLACE ORIGIN.  Con dicha herramienta no tendrás que borrar estaciones ni tener que cambiar de nuevo nombres ni añadir sensores o creaciones de pieza.', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 1, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (68, 18, 66, 'Eje mal posicionado en un robot de yams', 'Modificar posición de eje', 'Haz clic en el objeto inmediatamente inferior al objeto que contiene todos los cuerpos del robot. Despliega este objeto. Dentro, encontrarás cuerpos con las posiciones correctas de los ejes. Copia la posición del cuerpo deseado. Pega esta posición en el eje que necesitas corregir.', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 6, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (69, 18, 67, 'Solo tenemos dicha licencia en uno de los dongles, por lo que no podríamos importar un YAMS nuevo sobre uno antiguo sino tenemos dicho dongle conectado.', 'Usar YAMS Assistance para tener algún que otro hack.', '1. Abrir YAMS antiguo en YAMS Assistance. 2. Importar .psz del YAMS nuevo en el proyecto antiguo de YAMS. 3. Guardamos con el mismo nombre que tenía el proyecto antiguo. 4. Abres YAMS y ya tendrás ambos proyectos importados.', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 1, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (70, 18, 68, 'Cambiar el nombre de muchas estaciones a la vez', 'Seleccionando todas las estaciones y poniendoles un nombre comun , YAMS lo autocompleta con un numero al final en orden empezando desde el 0.', '1. Abrir Yams Assistance, Material Flow 2. Elegir el material donde vamos a introducir todas las estaciones 3. Introducir las estaciones, seleccionar todas y click derecho, editar. 4. Escribir el nombre comun de todas las estaciones. 5. YAMS autocompleta con un numero al final en el orden seleccionado.', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 9, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (71, 18, 69, 'Explicación de como añadir el SafeOP de los robots a YAMS', 'Añadir XML de cada SafeOP de los robots a YAMS, colocarlo en su posición correcta y añadirlo a su apartado en YAMS Assistance.', '1.  Creamos un nuevo object. 2. Importamos el archivo .xml del SafeOp del robot (Elegimos en tipo de archivo Kuka Safety Config XML files). 3. Colocamos el SafeOP en la posición correcta usando la funcionalidad "TRANSFORM". (En el apartado "FROM" colocamos el object creado, en "To" colocamos el frame de la base del robot, por ejemplo, 020RB_100__KR500_R2800-2_) Si el robot tiene séptimo eje, el frame correcto será $Base_World. Antes de dar a aplicar hay que comprobar que esté correctamente colocado. 4. En el apartado SafeOp de YAMS Assistance, añadimos el frame de la base del robot y escribrimos el nombre que tiene en ViPeR para la Shared Memory. Si tiene un séptimo eje, añadimos el  $Base_World. 5. Por último se añaden todos los bodies del SafeOp arrastrando el object creado al apartado de "Workspaces/Tools.', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 1, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (72, 18, 70, 'Tenemos que poner encima de cada robot su nombre', 'Hay que importar una libreria en YAMS y crear los nombres para cada robot', '1-En YAMS debemos añadir la libreria "Common_V_2.8" que podemos encontrar en la carpeta de "TechData". 2- En las carpetas de la librería, abrimos la de "Displays" y arrastramos 2 "String_4" dentro de un objeto nuevo que hayamos creado en "Resources". 3- Hacemos la traslacion de uno de los Strings (1.5 respecto a su propio eje x) para poder tener uno al lado del otro. 4-Ocultamos todos los cuerpos que podemos encontrar dentro de la carpeta que se ha creado con el String y deshabilitamos el archivo "String_4" que aparece al final de cada carpeta String. 5-Creamos un cuerpo para cada robot al que le tengamos que añadir nombre para añadirlo como Target Body y hacemos un Stonify con los numeros que nos interesa. En las carpetas podemos ver que cada body viene con un numero (que indica la posicion) y despues el numero o letra que representa. 6-Dentro del stonify añadimos cada body necesario.(Por ejemplo, para el robot 450RB100, añadimos del primer string los bodys: 0_4, 1_5, 2_0 y 3_R y del segundo string añadimos: 0_B, 1_1; 2_0 y 3_0) 7-Al hacer el apply deben aparecer el nombre completo visible como un solo cuerpo al que tenemos que hacerle la transformacion para que quede encima del robot.', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 9, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (73, 18, 71, 'Al importar la celda en Yams, el progreso se detiene y YAMS se congela.', 'Borrar los layouts de la celda', 'Debemos abrir la carpeta donde tenemos el process y buscar LAYOUT. Nos aparecerán varias carpetas que debemos borrar. Estos archivos insertan el layout debajo de la celda por lo que no nos aportan nada para la visualización.', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 9, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (74, 19, 72, 'Tras configurar correctamente la red, es decir, todas las Ips de los dispositivos están correctamente creadas pero sigue sin haber comunicación entre dos dispositivos.', 'Seleccionar interfaz de SIEMENS.', 'Para ello, vamos a Cambiar opciones del adaptador -> Click derecho en la interfaz a modificar -> Propiedades -> Seleccionamos "Siemens PLCSIM Virtual Switch"', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 4, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (75, 20, 73, 'Bajo rendimiento con Roboguide', 'Ejecutar en CMD: powercfg -duplicatescheme e9a42b02-d5df-448d-aa00-03f14749eb61', 'Ejecutar ese comando hace que el ordenador pueda deslimitarse en cuanto a potencia, maximizando el uso de la CPU, reduciendo la latencia y desactivando ahorros como el de energía.', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 12, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (76, 21, 74, 'Dejó de funcionar la conexión enre Fannuc Conect y DS Client en un mismo ordenador posteriormente se supo que habia sido consecuencia de una actualización de Windows', 'Deshabilitar las actualizaciones automáticas de Windows', '1. Presiona Window + R y escribe gpedit.msc después pulsa Enter Configuracion de equipo -> Plantillas administrativas -> Componentes de Windows -> Windows Update   En Windows Update vamos a entrar en tres carpetas y haremos algunas 	   	modificaciones.   Windows Update -> Administrar la experiencia del usuario final -> Configurar actualizaciones automáticas => Deshabilitada   Windows Update -> Administrar las actualizaciones ofrecidas desde Windows Update -> No incluyas controladores con las actualizaciones de Windows => Habilitada   Windows Update -> Directivas Heredadas -> No reiniciar automáticamente con usuarios que hayan iniciado sesión en instalaciones de actualizaciones automáticas => Habilitada                                                   Si falla la conexión entre Fannuc Conect y DS Client por una actualización de Windows se tendria que reinstalar Fanuct Robot Interface', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 13, 1);
INSERT INTO errors (id, area_id, topic_id, description_problem, solution, description_solution, status, created_at, updated_at, reported_by, proyect_id) VALUES (77, 1, 75, 'Incapacidad de conexión entre algunos ordenadores tras la instalación de Windows 11', 'Desactivar el FireWall de Windows', '1.Abrir el panel de control                                     2. Clica en Firewall de Windows Defender                                                                    3.Clicar en Configuración avanzada                   4.Clic derecho y propiedades en Windows Defender Firewall con seguridad avanzada en equipo local (arriba a la izquierda)                                                             5. Poner el perfil de dominio, el perfil privado y el perfil publico como inactivo', 'RESUELTO', '2024-01-01 00:00:00', '2024-01-01 00:00:00', 2, 1);
